```tsx
export const FormGroup: FC<FormGroupProps> = ({
  label, htmlFor, children, errorId, errorMessage,
  hint, hintId, required, className,
}) => {
  const generatedErrorId = useId();
  const generatedHintId = useId();
  const finalErrorId = errorId || generatedErrorId;
  const finalHintId = hintId || generatedHintId;

  const describedBy = [hint ? finalHintId : null, errorMessage ? finalErrorId : null].filter(Boolean).join(' ') || undefined;

  const enhancedChildren = React.Children.map(children, (child) => {
    if (React.isValidElement(child)) {
      return React.cloneElement(child, {
        'aria-describedby': describedBy,
      });
    }
    return child;
  });

  return (
    <div className={['form-group', className].filter(Boolean).join(' ')}>
      <label htmlFor={htmlFor} className="form-label">
        {label}
        {required && (
          <>
            <span aria-hidden="true" className="form-required-marker"> *</span>
            <VisuallyHidden> (required)</VisuallyHidden>
          </>
        )}
      </label>
      {hint && (
        <span id={finalHintId} className="form-hint">
          {hint}
        </span>
      )}
      {enhancedChildren}
      {errorMessage && <ErrorMessage id={finalErrorId} message={errorMessage} />}
    </div>
  );
};
```

